class Solution {
    public int decodeWays(String data) {
        return decode(data, 0);
    }

    private int decode(String data, int index) {
        if (index == data.length()) {
            return 1;
        }
        if (data.charAt(index) == '0') {
            return 0;
        }
        int count = decode(data, index + 1);
        if (index + 1 < data.length() && Integer.parseInt(data.substring(index, index + 2)) <= 26) {
            count += decode(data, index + 2);
        }
        return count;
    }
}

