class Solution {
    public int decodeWays(String data) {
        if (data == null || data.length() == 0) return 0;
        int n = data.length();
        int[] dp = new int[n + 1];
        dp[0] = 1; // Base case: empty string
        dp[1] = data.charAt(0) != '0' ? 1 : 0; // Single character decode

        for (int i = 2; i <= n; i++) {
            // Check single digit
            if (data.charAt(i - 1) != '0') {
                dp[i] += dp[i - 1];
            }
            // Check two digits
            int twoDigit = Integer.parseInt(data.substring(i - 2, i));
            if (twoDigit >= 10 && twoDigit <= 26) {
                dp[i] += dp[i - 2];
            }
        }
        return dp[n];
    }
}

