            dp[i] += dp[i-1]
        }
        if i > 1 {
            twoDigit := int(data[i-2]-'0')*10 + int(data[i-1]-'0')
            if twoDigit >= 10 && twoDigit <= 26 {
                dp[i] += dp[i-2]
            }
        }
    }

    return dp[len(data)]
